const result = await installLanguagePackages({
  language: "nodejs",
  packages: ["frontend"]
});
console.log(result.message);
console.log(result.output);

const result = await configureWorkflow({
  name: "Start application",
  command: "cd frontend && npm run dev",
  waitForPort: 5000,
  outputType: "webview"
});
console.log(JSON.stringify(result));

const status = await getWorkflowStatus({ name: "Start application", maxScrollbackLines: 30 });
console.log(`State: ${status.state}`);
console.log(`Ports: ${JSON.stringify(status.openPorts)}`);
console.log(`Output:\n${status.output}`);

const result = await deployConfig({
  deploymentTarget: "static",
  build: ["bash", "-c", "cd frontend && npm run build"],
  publicDir: "frontend/dist"
});
console.log(JSON.stringify(result));

